#include <stdio.h>
#include <unistd.h>
#include <string.h>

/* == EXEMPLE =======================================
 * Envoyer un entier via un pipe
 * pipe(fd) cree fd[0]=lecture, fd[1]=ecriture.
 * write dans fd[1], close fd[1], read depuis fd[0].
 * ================================================= */
void example_pipe_int(void) {
    int fd[2];
    pipe(fd);
    int value = 42;
    write(fd[1], &value, sizeof(value));
    close(fd[1]);
    int received = 0;
    read(fd[0], &received, sizeof(received));
    printf("Got: %d\n", received);
    close(fd[0]);
}
